@tailwind base;
@tailwind components;
@tailwind utilities;

/*
 * Windmill design tokens — resolved from WINDMILL_LIGHT_THEME_V3 (the real
 * production light theme) through generateThemeStyleObject(). Values are
 * stored as "r g b" triples so Tailwind can apply <alpha-value> opacities,
 * e.g. bg-accent/5. DO NOT hand-edit individual channels — regenerate from
 * the seed in apps/windmill-web/app/themes/themes.tsx if the theme changes.
 */
:root {
  /* base */
  --highlight: 59 130 246;
  --selected: 241 241 241;

  /* backgrounds */
  --bg-base: 255 255 255;
  --bg-surface: 253 253 253;
  --bg-surface-muted: 241 241 241;
  --bg-accent: 26 26 26;
  --bg-accent-muted: 141 141 141;
  --bg-primary-hover: 72 72 72;
  --bg-secondary-hover: 232 232 232;
  --bg-border: 229 229 229;
  --bg-error: 254 226 226;
  --bg-error-accent: 153 27 27;
  --bg-accent-inverse: 255 255 255;

  /* text */
  --text-primary: 34 34 34;
  --text-secondary: 91 91 93;
  --text-tertiary: 146 146 146;
  --text-accent: 26 26 26;
  --text-inverse: 238 237 234;
  --text-accent-inverse: 255 255 255;
  --text-error: 69 10 10;
  --text-error-accent-inverse: 254 226 226;

  /* borders */
  --border-default: 229 229 229;
  --border-strong: 202 202 202;
  --border-accent: 26 26 26;
  --border-muted: 241 241 241;
  --border-error: 252 165 165;
  --border-accent-inverse: 255 255 255;

  /* status — background + foreground pairs */
  --green-background: 209 245 227;
  --green-foreground: 76 183 130;
  --red-background: 251 232 228;
  --red-foreground: 229 63 79;
  --yellow-background: 255 255 234;
  --yellow-foreground: 233 146 67;
  --blue-background: 230 242 255;
  --blue-foreground: 72 133 255;
  --purple-background: 242 240 255;
  --purple-foreground: 176 128 243;
  --fuchsia-background: 248 230 247;
  --fuchsia-foreground: 255 69 149;
  --orange-background: 255 230 210;
  --orange-foreground: 255 107 36;

  /* sidebar */
  --sidebar-background: 250 250 250;
  --sidebar-foreground: 82 82 82;
  --sidebar-muted: 134 134 134;
  --sidebar-primary: 243 241 241;
  --sidebar-primary-foreground: 34 34 34;
  --sidebar-accent: 235 235 236;
  --sidebar-accent-foreground: 34 34 34;
  --sidebar-border: 239 239 239;
  --sidebar-ring: 59 130 246;

  /* gradient banner */
  --gradient-banner-background: 250 250 250;
  --gradient-banner-accent1: 230 69 255;
  --gradient-banner-accent2: 255 160 28;
  --gradient-banner-accent3: 97 133 240;

  /* radius — derived from theme.radius = 0.3 */
  --radius-none: 0rem;
  --radius-sm: 0.15rem;
  --radius-DEFAULT: 0.3rem;
  --radius-md: 0.45rem;
  --radius-lg: 0.6rem;
  --radius-xl: 1.2rem;
  --radius-full: 9999rem;

  /* border width */
  --border-width-DEFAULT: 1px;

  /* typography — DEFAULT_TYPOGRAPHY */
  --font-header-lg-size: 1.5rem;
  --font-header-lg-line-height: 1.25;
  --font-header-lg-letter-spacing: -0.0417em;
  --font-header-lg-weight: 500;
  --font-header-md-size: 1.125rem;
  --font-header-md-line-height: 1.25;
  --font-header-md-letter-spacing: -0.0278em;
  --font-header-md-weight: 500;
  --font-header-sm-size: 1rem;
  --font-header-sm-line-height: 1.25;
  --font-header-sm-letter-spacing: -0.03125em;
  --font-header-sm-weight: 500;
  --font-body-md-size: 1rem;
  --font-body-md-line-height: 1.5rem;
  --font-body-md-letter-spacing: 0;
  --font-body-md-weight: 400;
  --font-body-sm-size: 0.875rem;
  --font-body-sm-line-height: 1.25rem;
  --font-body-sm-letter-spacing: 0;
  --font-body-sm-weight: 450;
  --font-caption-size: 0.75rem;
  --font-caption-line-height: 1rem;
  --font-caption-letter-spacing: 0.03em;
  --font-caption-weight: 500;
  --font-ui-size: 0.8125rem;
  --font-ui-line-height: 1.25rem;
  --font-ui-letter-spacing: 0;
  --font-ui-weight: 500;
}

@layer base {
  body {
    background-color: rgb(var(--bg-base));
    color: rgb(var(--text-primary));
    font-family: "Inter", ui-sans-serif, system-ui, sans-serif;
    -webkit-font-smoothing: antialiased;
  }
}

/* Custom component utilities ported from packages/ui/src/input.css —
   used by Button (icon intent), StatusIcon, Chip, Card, etc. */
@layer components {
  .circle-1 { @apply flex h-1 w-1 items-center justify-center rounded-full; }
  .circle-2 { @apply flex size-2 items-center justify-center rounded-full; }
  .circle-3 { @apply flex size-3 items-center justify-center rounded-full; }
  .circle-4 { @apply flex size-4 items-center justify-center rounded-full; }
  .circle-5 { @apply flex size-5 items-center justify-center rounded-full; }
  .circle-6 { @apply flex size-6 items-center justify-center rounded-full; }
  .circle-8 { @apply flex size-8 items-center justify-center rounded-full; }
  .circle-10 { @apply flex size-10 items-center justify-center rounded-full; }
  .circle-12 { @apply flex size-12 items-center justify-center rounded-full; }
  .circle-14 { @apply flex size-14 items-center justify-center rounded-full; }
  .card { @apply border bg-surface rounded-md block; }
}

/* Marquee keyframes + utilities ported verbatim from packages/ui/tailwind.config.cjs
   (theme.extend.keyframes/animation). Used by Marquee.tsx, which drives speed/gap
   via the --duration / --gap CSS vars set on its own classNames. */
@keyframes marquee {
  from { transform: translateX(0); }
  to { transform: translateX(calc(-100% - var(--gap))); }
}
@keyframes marquee-vertical {
  from { transform: translateY(0); }
  to { transform: translateY(calc(-100% - var(--gap))); }
}
@layer utilities {
  .animate-marquee {
    animation: marquee var(--duration) linear infinite;
  }
  .animate-marquee-vertical {
    animation: marquee-vertical var(--duration) linear infinite;
  }
}

import type { Config } from "tailwindcss";
import defaultTheme from "tailwindcss/defaultTheme";

/*
 * Faithful port of packages/ui/tailwind.config.cjs, trimmed to what
 * prototypes need. All colors resolve from the CSS variables defined in
 * app/globals.css. Keep class names identical to the real design system so
 * components copy over 1:1 (text-primary, bg-surface, bg-accent, etc.).
 */
const config: Config = {
  content: ["./app/**/*.{ts,tsx}", "./components/**/*.{ts,tsx}"],
  darkMode: "class",
  theme: {
    extend: {
      fontFamily: {
        sans: ["Inter", ...defaultTheme.fontFamily.sans],
        mono: ["Geist Mono", ...defaultTheme.fontFamily.mono],
        serif: ["Recoleta", ...defaultTheme.fontFamily.serif],
      },
      screens: { xs: "480px" },
      // Tremor tokens (ported verbatim from packages/ui/tailwind.config.cjs) so the
      // recharts-based charts render with the right content/border/background colors.
      // These flow into text-/bg-/border-/stroke-/fill-tremor-* via the ...theme("colors")
      // spreads in each color map below.
      colors: {
        tremor: {
          brand: {
            faint: "#eff6ff",
            muted: "#bfdbfe",
            subtle: "#60a5fa",
            DEFAULT: "#3b82f6",
            emphasis: "#1d4ed8",
            inverted: "#ffffff",
          },
          background: {
            muted: "#f9fafb",
            subtle: "#f3f4f6",
            DEFAULT: "#ffffff",
            emphasis: "#374151",
          },
          border: { DEFAULT: "#e5e7eb" },
          ring: { DEFAULT: "#e5e7eb" },
          content: {
            subtle: "#9ca3af",
            DEFAULT: "#6b7280",
            emphasis: "#374151",
            strong: "#111827",
            inverted: "#ffffff",
          },
        },
      },
      borderRadius: {
        "tremor-small": "0.375rem",
        "tremor-default": "0.5rem",
        "tremor-full": "9999px",
      },
      boxShadow: {
        "tremor-input": "0 1px 2px 0 rgb(0 0 0 / 0.05)",
        "tremor-card": "0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1)",
        "tremor-dropdown": "0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1)",
      },
      fontSize: {
        "header-lg": [
          "var(--font-header-lg-size)",
          {
            lineHeight: "var(--font-header-lg-line-height)",
            letterSpacing: "var(--font-header-lg-letter-spacing)",
            fontWeight: "var(--font-header-lg-weight)",
          },
        ],
        "header-md": [
          "var(--font-header-md-size)",
          {
            lineHeight: "var(--font-header-md-line-height)",
            letterSpacing: "var(--font-header-md-letter-spacing)",
            fontWeight: "var(--font-header-md-weight)",
          },
        ],
        "header-sm": [
          "var(--font-header-sm-size)",
          {
            lineHeight: "var(--font-header-sm-line-height)",
            letterSpacing: "var(--font-header-sm-letter-spacing)",
            fontWeight: "var(--font-header-sm-weight)",
          },
        ],
        "body-md": [
          "var(--font-body-md-size)",
          {
            lineHeight: "var(--font-body-md-line-height)",
            letterSpacing: "var(--font-body-md-letter-spacing)",
            fontWeight: "var(--font-body-md-weight)",
          },
        ],
        "body-sm": [
          "var(--font-body-sm-size)",
          {
            lineHeight: "var(--font-body-sm-line-height)",
            letterSpacing: "var(--font-body-sm-letter-spacing)",
            fontWeight: "var(--font-body-sm-weight)",
          },
        ],
        caption: [
          "var(--font-caption-size)",
          {
            lineHeight: "var(--font-caption-line-height)",
            letterSpacing: "var(--font-caption-letter-spacing)",
            fontWeight: "var(--font-caption-weight)",
          },
        ],
        ui: [
          "var(--font-ui-size)",
          {
            lineHeight: "var(--font-ui-line-height)",
            letterSpacing: "var(--font-ui-letter-spacing)",
            fontWeight: "var(--font-ui-weight)",
          },
        ],
        "tremor-label": ["0.75rem", { lineHeight: "1rem" }],
        "tremor-default": ["0.875rem", { lineHeight: "1.25rem" }],
        "tremor-title": ["1.125rem", { lineHeight: "1.75rem" }],
        "tremor-metric": ["1.875rem", { lineHeight: "2.25rem" }],
      },
    },
    borderRadius: {
      none: "0",
      sm: "var(--radius-sm)",
      DEFAULT: "var(--radius-DEFAULT)",
      md: "var(--radius-md)",
      lg: "var(--radius-lg)",
      xl: "var(--radius-xl)",
      full: "var(--radius-full)",
    },
    borderWidth: { 0: "0", 1: "1px", DEFAULT: "var(--border-width-DEFAULT)", 2: "2px", 4: "4px" },
    backgroundColor: ({ theme }) => ({
      ...theme("colors"),
      transparent: "transparent",
      highlight: "rgb(var(--highlight) / <alpha-value>)",
      selected: "rgb(var(--selected) / <alpha-value>)",
      base: { DEFAULT: "rgb(var(--bg-base) / <alpha-value>)" },
      surface: {
        DEFAULT: "rgb(var(--bg-surface) / <alpha-value>)",
        muted: "rgb(var(--bg-surface-muted) / <alpha-value>)",
      },
      primary: { hover: "rgb(var(--bg-primary-hover) / <alpha-value>)" },
      secondary: { hover: "rgb(var(--bg-secondary-hover) / <alpha-value>)" },
      accent: {
        DEFAULT: "rgb(var(--bg-accent) / <alpha-value>)",
        inverse: "rgb(var(--bg-accent-muted) / <alpha-value>)",
      },
      error: {
        DEFAULT: "rgb(var(--bg-error) / <alpha-value>)",
        accent: "rgb(var(--bg-error-accent) / <alpha-value>)",
      },
      green: {
        DEFAULT: "rgb(var(--green-background) / <alpha-value>)",
        foreground: "rgb(var(--green-foreground) / <alpha-value>)",
      },
      red: {
        DEFAULT: "rgb(var(--red-background) / <alpha-value>)",
        foreground: "rgb(var(--red-foreground) / <alpha-value>)",
      },
      yellow: {
        DEFAULT: "rgb(var(--yellow-background) / <alpha-value>)",
        foreground: "rgb(var(--yellow-foreground) / <alpha-value>)",
      },
      blue: {
        DEFAULT: "rgb(var(--blue-background) / <alpha-value>)",
        foreground: "rgb(var(--blue-foreground) / <alpha-value>)",
      },
      purple: {
        DEFAULT: "rgb(var(--purple-background) / <alpha-value>)",
        foreground: "rgb(var(--purple-foreground) / <alpha-value>)",
      },
      fuchsia: {
        DEFAULT: "rgb(var(--fuchsia-background) / <alpha-value>)",
        foreground: "rgb(var(--fuchsia-foreground) / <alpha-value>)",
      },
      orange: {
        DEFAULT: "rgb(var(--orange-background) / <alpha-value>)",
        foreground: "rgb(var(--orange-foreground) / <alpha-value>)",
      },
      sidebar: {
        DEFAULT: "rgb(var(--sidebar-background) / <alpha-value>)",
        accent: "rgb(var(--sidebar-accent) / <alpha-value>)",
      },
      gradientBanner: {
        DEFAULT: "rgb(var(--gradient-banner-background) / <alpha-value>)",
        accent1: "rgb(var(--gradient-banner-accent1) / <alpha-value>)",
        accent2: "rgb(var(--gradient-banner-accent2) / <alpha-value>)",
        accent3: "rgb(var(--gradient-banner-accent3) / <alpha-value>)",
      },
    }),
    textColor: ({ theme }) => ({
      ...theme("colors"),
      DEFAULT: "rgb(var(--text-primary) / <alpha-value>)",
      primary: "rgb(var(--text-primary) / <alpha-value>)",
      secondary: "rgb(var(--text-secondary) / <alpha-value>)",
      tertiary: "rgb(var(--text-tertiary) / <alpha-value>)",
      accent: {
        DEFAULT: "rgb(var(--text-accent) / <alpha-value>)",
        inverse: "rgb(var(--text-accent-inverse) / <alpha-value>)",
      },
      inverse: "rgb(var(--text-inverse) / <alpha-value>)",
      error: { DEFAULT: "rgb(var(--text-error) / <alpha-value>)" },
      green: "rgb(var(--green-foreground) / <alpha-value>)",
      red: "rgb(var(--red-foreground) / <alpha-value>)",
      yellow: "rgb(var(--yellow-foreground) / <alpha-value>)",
      blue: "rgb(var(--blue-foreground) / <alpha-value>)",
      purple: "rgb(var(--purple-foreground) / <alpha-value>)",
      fuchsia: "rgb(var(--fuchsia-foreground) / <alpha-value>)",
      orange: "rgb(var(--orange-foreground) / <alpha-value>)",
    }),
    borderColor: ({ theme }) => ({
      ...theme("colors"),
      DEFAULT: "rgb(var(--border-default) / <alpha-value>)",
      base: "rgb(var(--border-default) / <alpha-value>)",
      accent: {
        DEFAULT: "rgb(var(--border-accent) / <alpha-value>)",
        inverse: "rgb(var(--bg-accent-muted) / <alpha-value>)",
      },
      strong: "rgb(var(--border-strong) / <alpha-value>)",
      surface: {
        DEFAULT: "rgb(var(--bg-surface) / <alpha-value>)",
        muted: "rgb(var(--bg-surface-muted) / <alpha-value>)",
      },
      muted: "rgb(var(--border-muted) / <alpha-value>)",
      error: "rgb(var(--border-error) / <alpha-value>)",
    }),
    ringColor: ({ theme }) => ({
      ...theme("colors"),
      DEFAULT: "rgb(var(--border-default) / <alpha-value>)",
      highlight: "rgb(var(--highlight) / <alpha-value>)",
      accent: "rgb(var(--border-accent) / <alpha-value>)",
    }),
    placeholderColor: ({ theme }) => ({
      ...theme("colors"),
      secondary: "rgb(var(--text-secondary) / <alpha-value>)",
      tertiary: "rgb(var(--text-tertiary) / <alpha-value>)",
    }),
  },
  plugins: [],
};

export default config;
